import{c as t,Q as e,j as r,m as l}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"使用政策（AUP）","description":"","frontmatter":{},"headers":[],"relativePath":"tos/aup.md","filePath":"tos/aup.md","lastUpdated":1779875536000}'),i={name:"tos/aup.md"};function h(o,a,d,n,s,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="使用政策-aup" tabindex="-1">使用政策（AUP） <a class="header-anchor" href="#使用政策-aup" aria-label="Permalink to &quot;使用政策（AUP）&quot;">​</a></h1><p><a href="https://www.suirenai.com" target="_blank" rel="noreferrer">Suirenai Team</a>2025/12/13大约 9 分钟政策</p><hr><p>重要提示</p><p>本文档根据 Suirenai「使用政策」页面内容整理（生效日期：2025 年 10 月 30 日）。<br> 如本文档与官网存在差异或版本更新，请以官网页面为准：<br><a href="https://www.suirenai.com/usage-policy" target="_blank" rel="noreferrer">https://www.suirenai.com/usage-policy</a></p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>文档名称</td><td>使用政策（可接受使用政策 / AUP）</td></tr><tr><td>生效日期</td><td>2025 年 10 月 30 日</td></tr><tr><td>来源链接</td><td><a href="https://www.suirenai.com/usage-policy" target="_blank" rel="noreferrer">https://www.suirenai.com/usage-policy</a></td></tr><tr><td>整理时间</td><td>2025 年 12 月 13 日</td></tr><tr><td>适用对象</td><td>任何可以向 Suirenai 的产品和/或服务提交输入的人（含授权经销商或直通访问）</td></tr><tr><td>目标</td><td>帮助用户保持安全并促进负责任地使用产品与服务</td></tr></tbody></table><ul><li><a href="./.html">概述</a></li><li><a href="./.html">通用使用标准</a><ul><li><a href="./.html">不得违反适用法律或从事非法活动</a></li><li><a href="./.html">不得危害关键基础设施</a></li><li><a href="./.html">不得危害计算机或网络系统</a></li><li><a href="./.html">不得开发或设计武器</a></li><li><a href="./.html">不得煽动暴力或仇恨行为</a></li><li><a href="./.html">不得侵犯隐私或身份权利</a></li><li><a href="./.html">不得危害儿童安全</a></li><li><a href="./.html">不得创建心理或情感上有害的内容</a></li><li><a href="./.html">不得创建或传播错误信息</a></li><li><a href="./.html">不得破坏民主进程或参与有针对性的竞选活动</a></li><li><a href="./.html">不得用于刑事司法、审查、监视或被禁止的执法目的</a></li><li><a href="./.html">不得从事欺诈、滥用或掠夺性做法</a></li><li><a href="./.html">不得滥用我们的平台</a></li><li><a href="./.html">不得生成性露骨内容</a></li></ul></li><li><a href="./.html">高风险用例要求</a></li><li><a href="./.html">其他用例指南</a></li><li><a href="./.html">相关链接</a></li></ul><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>我们的使用政策（也称为“可接受使用政策”或 “AUP”）适用于任何可以向 Suirenai 的产品和/或服务提交输入的人，包括通过任何授权经销商或直通访问，我们将所有这些人称为“用户”。使用政策旨在帮助我们的用户保持安全并促进负责任地使用我们的产品和服务。</p><p>使用政策根据谁可以使用我们的产品以及出于什么目的进行分类。随着我们的技术和相关风险的发展或我们了解意外风险，我们将更新我们的政策。</p><p>阅读建议</p><ul><li>如果你在产品中面向终端用户提供输出，请优先阅读「高风险用例要求」与「其他用例指南」。</li><li>如果你不确定某个用途是否合规，建议先按「通用使用标准」逐条自检。</li></ul><h2 id="通用使用标准" tabindex="-1">通用使用标准 <a class="header-anchor" href="#通用使用标准" aria-label="Permalink to &quot;通用使用标准&quot;">​</a></h2><p>我们的通用使用标准适用于所有用户和所有用例。</p><h3 id="不得违反适用法律或从事非法活动" tabindex="-1">不得违反适用法律或从事非法活动 <a class="header-anchor" href="#不得违反适用法律或从事非法活动" aria-label="Permalink to &quot;不得违反适用法律或从事非法活动&quot;">​</a></h3><p>不得使用我们的服务从事、促进或鼓励非法活动，包括虐待、剥削、伤害或试图伤害儿童。</p><h3 id="不得危害关键基础设施" tabindex="-1">不得危害关键基础设施 <a class="header-anchor" href="#不得危害关键基础设施" aria-label="Permalink to &quot;不得危害关键基础设施&quot;">​</a></h3><p>不得使用我们的服务来伤害、破坏或扰乱关键基础设施，包括但不限于电信、医疗保健、能源、运输、供水、金融服务和选举基础设施的技术基础设施。</p><h3 id="不得危害计算机或网络系统" tabindex="-1">不得危害计算机或网络系统 <a class="header-anchor" href="#不得危害计算机或网络系统" aria-label="Permalink to &quot;不得危害计算机或网络系统&quot;">​</a></h3><p>不得使用我们的服务开发或散布恶意软件，或以其他方式危害、破坏、未经授权访问或控制任何计算机系统。</p><h3 id="不得开发或设计武器" tabindex="-1">不得开发或设计武器 <a class="header-anchor" href="#不得开发或设计武器" aria-label="Permalink to &quot;不得开发或设计武器&quot;">​</a></h3><p>不得使用我们的服务开发武器、军事应用、监控技术或以其他方式伤害人类的其他技术，包括设计、开发、生产或测试核、生物、化学或辐射武器、军用级网络能力、导弹、无人机或自主武器系统。</p><h3 id="不得煽动暴力或仇恨行为" tabindex="-1">不得煽动暴力或仇恨行为 <a class="header-anchor" href="#不得煽动暴力或仇恨行为" aria-label="Permalink to &quot;不得煽动暴力或仇恨行为&quot;">​</a></h3><p>不得使用我们的服务煽动、促进、宣传或美化针对个人或群体的极端暴力或基于身份的暴力，也不得宣传、美化、促进或提倡针对受保护群体的仇恨或对其进行贬低、人格化或非人化。</p><h3 id="不得侵犯隐私或身份权利" tabindex="-1">不得侵犯隐私或身份权利 <a class="header-anchor" href="#不得侵犯隐私或身份权利" aria-label="Permalink to &quot;不得侵犯隐私或身份权利&quot;">​</a></h3><p>不得使用我们的服务从事、促进、煽动或促使跟踪、骚扰、欺凌或其他形式的骚扰，或通过其他非法或未经授权的方式危害或侵犯人们的隐私权、公开权或其他法律权利，包括创建用于识别私人或受限区域中的人的面部识别系统，或在数据泄露后使用非公开个人信息进行跟踪、骚扰、身份盗用或相关犯罪。</p><h3 id="不得危害儿童安全" tabindex="-1">不得危害儿童安全 <a class="header-anchor" href="#不得危害儿童安全" aria-label="Permalink to &quot;不得危害儿童安全&quot;">​</a></h3><p>不得使用我们的服务创建、获取或传播虐待或利用儿童的内容，包括但不限于性虐待儿童材料（CSAM）或赞美、美化或鼓励对儿童进行性虐待的内容。</p><h3 id="不得创建心理或情感上有害的内容" tabindex="-1">不得创建心理或情感上有害的内容 <a class="header-anchor" href="#不得创建心理或情感上有害的内容" aria-label="Permalink to &quot;不得创建心理或情感上有害的内容&quot;">​</a></h3><p>不得使用我们的服务自动生成或传播旨在对人们造成心理或情感伤害的内容，包括促进自残或自杀，或通过欺凌、骚扰或虐待进行有针对性的骚扰。</p><h3 id="不得创建或传播错误信息" tabindex="-1">不得创建或传播错误信息 <a class="header-anchor" href="#不得创建或传播错误信息" aria-label="Permalink to &quot;不得创建或传播错误信息&quot;">​</a></h3><p>不得使用我们的服务大规模创建或传播经济、政治或社会伤害的虚假、不准确、误导或欺骗性内容，包括有关公共卫生紧急情况、公民程序或政治或公民领导人的此类内容。</p><h3 id="不得破坏民主进程或参与有针对性的竞选活动" tabindex="-1">不得破坏民主进程或参与有针对性的竞选活动 <a class="header-anchor" href="#不得破坏民主进程或参与有针对性的竞选活动" aria-label="Permalink to &quot;不得破坏民主进程或参与有针对性的竞选活动&quot;">​</a></h3><p>不得使用我们的服务破坏、损害或破坏公平和开放的民主或公民进程，包括通过虚假信息的分发、针对性地压制投票或阻碍其他人参加公民进程的能力。不得使用我们的服务进行政治竞选或游说，或生成旨在大规模影响政治、司法、社会或经济结果的竞选材料，包括宣传活动的输出、带有政治意见的个性化或有针对性的信息、交互式竞选活动聊天机器人或选民压制材料。</p><h3 id="不得用于刑事司法、审查、监视或被禁止的执法目的" tabindex="-1">不得用于刑事司法、审查、监视或被禁止的执法目的 <a class="header-anchor" href="#不得用于刑事司法、审查、监视或被禁止的执法目的" aria-label="Permalink to &quot;不得用于刑事司法、审查、监视或被禁止的执法目的&quot;">​</a></h3><p>不得使用我们的服务进行任何预测性警务、起诉、量刑或拘留决定、测谎或类似应用、审查或大规模监视或任何其他被禁止的执法目的。</p><h3 id="不得从事欺诈、滥用或掠夺性做法" tabindex="-1">不得从事欺诈、滥用或掠夺性做法 <a class="header-anchor" href="#不得从事欺诈、滥用或掠夺性做法" aria-label="Permalink to &quot;不得从事欺诈、滥用或掠夺性做法&quot;">​</a></h3><p>不得使用我们的服务创建或传播欺诈性、虚假或误导性内容，旨在欺骗、欺诈或剥削人们，包括但不限于计划、诈骗和其他欺诈行为。不得使用我们的服务冒充个人、组织或实体以欺骗、误导或欺诈他人。不得使用我们的服务进行或促进赌博、发薪日贷款或高成本信贷产品，或其他剥削性经济活动。不得使用我们的服务进行其他非法、欺诈或欺骗性活动，或生成或传播垃圾邮件。</p><h3 id="不得滥用我们的平台" tabindex="-1">不得滥用我们的平台 <a class="header-anchor" href="#不得滥用我们的平台" aria-label="Permalink to &quot;不得滥用我们的平台&quot;">​</a></h3><p>不得违反我们的平台政策使用我们的服务，包括但不限于尝试破坏我们的保护措施，逃避模型的内置限制，以任何未经授权的方式提取模型权重，或违反我们在 Suirenai 上实施的服务使用限制，包括费率限制。</p><h3 id="不得生成性露骨内容" tabindex="-1">不得生成性露骨内容 <a class="header-anchor" href="#不得生成性露骨内容" aria-label="Permalink to &quot;不得生成性露骨内容&quot;">​</a></h3><p>不得使用我们的服务生成性露骨内容，包括有露骨目的或性满足的内容。这包括使用我们的服务生成色情内容（无论是文本还是图像）。此限制不适用于使用我们的服务进行合法的性和生殖健康用途、科学、教育或艺术用途的内容。</p><h2 id="高风险用例要求" tabindex="-1">高风险用例要求 <a class="header-anchor" href="#高风险用例要求" aria-label="Permalink to &quot;高风险用例要求&quot;">​</a></h2><p>某些用例由于影响对公共福利和社会公平至关重要的领域而构成更高的伤害风险。对于这些用例，鉴于对个人和消费者的潜在风险，我们认为应整合相关的人类专业知识，并且最终用户应该意识到 AI 何时参与产生输出。</p><p>因此，对于下面描述的“高风险用例”，我们要求您实施这些额外的安全措施：</p><p>额外安全措施（必须）</p><ul><li><strong>人在回路中：</strong> 在使用我们的产品或服务提供直接影响个人或消费者的建议、推荐或主观决策时，该领域的合格专业人员必须在传播或最终确定之前审查内容或决策。您或您的组织对该信息的准确性和适当性负责。</li><li><strong>披露：</strong> 如果模型输出直接呈现给个人或消费者，您必须向他们披露您正在使用 AI 来帮助生成您的建议、决策或推荐。此披露必须至少在每个会话开始时提供。</li></ul><p>“高风险用例”包括：</p><table tabindex="0"><thead><tr><th>类别</th><th>说明</th></tr></thead><tbody><tr><td>法律</td><td>与法律解释、法律指导或具有法律影响的决策有关的用例</td></tr><tr><td>医疗保健</td><td>与医疗保健决策、医疗诊断、患者护理、治疗、心理健康或其他医疗指导有关的用例。健康建议（例如，关于睡眠、压力、营养、锻炼等的建议）不属于此类别</td></tr><tr><td>保险</td><td>与健康、人寿、财产、残疾或其他类型的保险承保、索赔处理或承保决策有关的用例</td></tr><tr><td>金融</td><td>与财务决策有关的用例，包括投资建议、贷款批准和确定财务资格或信用worthiness</td></tr><tr><td>就业和住房</td><td>与有关个人就业能力的决策、简历筛选、招聘工具或其他就业决定或关于住房资格的决策（包括租赁和住房贷款）有关的用例</td></tr><tr><td>学术测试、认证和录取</td><td>与管理学校录取（包括评估、评分或排名潜在学生）、语言能力或专业认证考试的标准化测试公司有关的用例；评估和认证教育机构的机构</td></tr><tr><td>媒体或专业新闻内容</td><td>与使用我们的产品或服务自动生成内容并将其发布以供外部消费有关的用例</td></tr></tbody></table><h2 id="其他用例指南" tabindex="-1">其他用例指南 <a class="header-anchor" href="#其他用例指南" aria-label="Permalink to &quot;其他用例指南&quot;">​</a></h2><p>以下用例（无论它们是否是高风险用例）必须遵守提供的其他指南。</p><ul><li>所有面向消费者的聊天机器人，包括任何面向外部或交互式 AI 代理，必须向用户披露他们正在与 AI 而不是人类交互。此披露必须至少在每次聊天会话开始时提供。</li><li>服务未成年人的产品，包括为未成年人提供直接与包含我们 API 的产品交互能力的组织，必须遵守我们帮助中心文章中概述的附加指南。</li><li>代理用例仍必须遵守使用政策。我们在此帮助中心文章中提供了在代理用例背景下使用政策禁止的示例。</li><li>我们连接器目录中列出的模型上下文协议（MCP）服务器必须遵守我们的目录政策。</li></ul><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li>使用政策（本页来源）：<a href="https://www.suirenai.com/usage-policy" target="_blank" rel="noreferrer">https://www.suirenai.com/usage-policy</a></li><li>服务条款：<a href="https://www.suirenai.com/terms" target="_blank" rel="noreferrer">https://www.suirenai.com/terms</a></li><li>服务特定条款：<a href="https://www.suirenai.com/service-specific-terms" target="_blank" rel="noreferrer">https://www.suirenai.com/service-specific-terms</a></li><li>支持的国家和地区：<a href="https://www.suirenai.com/supported-regions" target="_blank" rel="noreferrer">https://www.suirenai.com/supported-regions</a></li></ul>',54)])])}const m=t(i,[["render",h]]);export{c as __pageData,m as default};
